// // This module implements an 8-bit synchronous up counter with a negative edge triggered clock, an active high synchronous reset, a disable signal, and a release signal. The counter should increment by 1 on every negative clock edge when disable is low and reset is not asserted.
module down_counter (
    input clk,
    input reset_n,
    input en,
    input hold,
    output reg [7:0] q);

always @(posedge clk or negedge reset_n) begin
    if (!reset_n)
        q <= 8'b00000000;
    else if (hold)
        q <= q;
    else if (en)
        q <= q - 1;
end

endmodule
